const CACHE_NAME="fnb-cache-v1",STATIC_ASSETS=["/","/index.html","/offline.html","/css/styles.css","/js/main.js","/js/theme.js","/js/menu.js","/js/cart.js","/js/checkout.js","/js/i18n.js","/manifest.json","/images/favicon.svg","/images/favicon-192x192.png","/images/favicon-512x512.png"];async function syncOrders(){}self.addEventListener("install",e=>{e.waitUntil(caches.open(CACHE_NAME).then(e=>e.addAll(STATIC_ASSETS)).then(()=>self.skipWaiting()))}),self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(e=>Promise.all(e.filter(e=>e!==CACHE_NAME).map(e=>caches.delete(e)))).then(()=>self.clients.claim()))}),self.addEventListener("fetch",e=>{"GET"===e.request.method&&e.request.url.startsWith(self.location.origin)&&e.respondWith(fetch(e.request).then(t=>{const n=t.clone();return 200===t.status&&caches.open(CACHE_NAME).then(t=>{t.put(e.request,n)}),t}).catch(()=>caches.match(e.request).then(t=>t||("navigate"===e.request.mode?caches.match("/offline.html"):new Response("Offline - No cached version available",{status:503,statusText:"Service Unavailable"})))))}),self.addEventListener("push",e=>{const t={body:e.data?.text()||"Đơn hàng của bạn đã sẵn sàng!",icon:"/images/favicon-192x192.png",badge:"/images/favicon-192x192.png",vibrate:[100,50,100],data:{dateOfArrival:Date.now(),primaryKey:1},actions:[{action:"view",title:"Xem đơn hàng"},{action:"close",title:"Đóng"}]};e.waitUntil(self.registration.showNotification("F&B Container Café",t))}),self.addEventListener("notificationclick",e=>{e.notification.close(),"view"===e.action&&e.waitUntil(clients.openWindow("/?tab=orders"))}),self.addEventListener("sync",e=>{"sync-orders"===e.tag&&e.waitUntil(syncOrders())});